    static void WG\(IntPtr p, int o, Guid g\) { byte[] b=g.ToByteArray\(\); for\(int i=0;i<16;i++\) Marshal.WriteByte\(p,o+i,b[i]\); }
    static void WP\(IntPtr p, int o, IntPtr v\) { Marshal.WriteInt64\(p,o,v.ToInt64\(\)\); }
    static IntPtr BF\(Guid fk, IntPtr nm, Guid lk, Guid sk, uint nc, IntPtr cp, uint at\) {
        IntPtr p=Marshal.AllocHGlobal\(200\);
        for\(int i=0;i<200;i++\) Marshal.WriteByte\(p,i,0\);
        WG\(p,0,fk\); WP\(p,16,nm\); WG\(p,64,lk\); WG\(p,80,sk\);
        Marshal.WriteInt32\(p,112,\(int\)nc\); WP\(p,120,cp\); Marshal.WriteInt32\(p,128,\(int\)at\);
        return p;
    }
    static IntPtr BC_U32\(Guid field, uint ip\) {
        IntPtr p=Marshal.AllocHGlobal\(40\);
        for\(int i=0;i<40;i++\) Marshal.WriteByte\(p,i,0\);
        WG\(p,0,field\); Marshal.WriteInt32\(p,24,3\); Marshal.WriteInt32\(p,32,\(int\)ip\);
        return p;
    }
    static IntPtr BC_V4M\(Guid field, uint ip, out IntPtr maskPtr\) {
        maskPtr=Marshal.AllocHGlobal\(8\);
        Marshal.WriteInt32\(maskPtr,0,\(int\)ip\);
        Marshal.WriteInt32\(maskPtr,4,unchecked\(\(int\)0xFFFFFFFF\)\);
        IntPtr p=Marshal.AllocHGlobal\(40\);
        for\(int i=0;i<40;i++\) Marshal.WriteByte\(p,i,0\);
        WG\(p,0,field\); Marshal.WriteInt32\(p,24,0x100\); WP\(p,32,maskPtr\);
        return p;
    }
    static uint TF\(IntPtr engine, Guid fk, Guid lk, Guid sk, uint nc, IntPtr cp, uint at, out ulong fid\) {
        fid=0;
        IntPtr nm=Marshal.StringToHGlobalUni\(\\"DBD-Test\\"\);
        IntPtr fp=BF\(fk,nm,lk,sk,nc,cp,at\);
        uint r=FwpmFilterAdd0\(engine,fp,IntPtr.Zero,out fid\);
        Marshal.FreeHGlobal\(fp\); Marshal.FreeHGlobal\(nm\);
        return r;
    }
    public static string Run\(\) {
        IntPtr h; uint r;
        r=FwpmEngineOpen0\(IntPtr.Zero,0xFFFFFFFF,IntPtr.Zero,IntPtr.Zero,out h\);
        if\(r!=0\) return \\"EngineOpen FAIL 0x\\"+r.ToString\(\\"X8\\"\);
        var sb=new StringBuilder\(\);
        Guid layer=new Guid\(\\"c38d57d1-05a7-4c33-904f-7fbceee60e82\\"\);
        Guid subkey=new Guid\(\\"dbd00002-0000-0000-0000-000000000001\\"\);
        Guid ipField=new Guid\(\\"4cd62a49-59c3-4969-b7f3-bda5d32890a4\\"\);
        uint ip=0x01010101;
        // Add sublayer
        FWPM_SUBLAYER0 sl=new FWPM_SUBLAYER0\(\);
        sl.subLayerKey=subkey;
        IntPtr snm=Marshal.StringToHGlobalUni\(\\"DBD-Test-SL\\"\);
        sl.displayData.name=snm; sl.weight=0x8000;
        r=FwpmSubLayerAdd0\(h,ref sl,IntPtr.Zero\); Marshal.FreeHGlobal\(snm\);
        sb.Append\(\\"Sublayer: 0x\\"+r.ToString\(\\"X8\\"\)+\\"\\\\n\\"\);
        ulong fid; IntPtr cp;
        // E: PERMIT + condition FWP_UINT32
        cp=BC_U32\(ipField,ip\);
        r=TF\(h,new Guid\(\\"dbd00002-0000-0000-0000-0000000000E1\\"\),layer,subkey,1,cp,0x1002,out fid\);
        Marshal.FreeHGlobal\(cp\);
        sb.Append\(\\"E\(PERMIT+U32\): 0x\\"+r.ToString\(\\"X8\\"\)+\\" fid=\\"+fid+\\"\\\\n\\"\);
        if\(r==0\) FwpmFilterDeleteById0\(h,fid\);
        // F: BLOCK + condition FWP_V4_ADDR_AND_MASK
        IntPtr mp; cp=BC_V4M\(ipField,ip,out mp\);
        r=TF\(h,new Guid\(\\"dbd00002-0000-0000-0000-0000000000F1\\"\),layer,subkey,1,cp,0x1001,out fid\);
        Marshal.FreeHGlobal\(cp\); Marshal.FreeHGlobal\(mp\);
        sb.Append\(\\"F\(BLOCK+V4M\): 0x\\"+r.ToString\(\\"X8\\"\)+\\" fid=\\"+fid+\\"\\\\n\\"\);
        if\(r==0\) FwpmFilterDeleteById0\(h,fid\);
        // G: BLOCK + condition FWP_UINT32 but using BUILT-IN sublayer FWPM_SUBLAYER_UNIVERSAL
        Guid builtinSL=new Guid\(\\"eebecc03-ced4-4380-819a-2734397b2b74\\"\);
        cp=BC_U32\(ipField,ip\);
        r=TF\(h,new Guid\(\\"dbd00002-0000-0000-0000-0000000000G1\\".Replace\(\\"G\\",\\"9\\"\)\),layer,builtinSL,1,cp,0x1001,out fid\);
        Marshal.FreeHGlobal\(cp\);
        sb.Append\(\\"G\(BLOCK+U32+builtinSL\): 0x\\"+r.ToString\(\\"X8\\"\)+\\" fid=\\"+fid+\\"\\\\n\\"\);
        if\(r==0\) FwpmFilterDeleteById0\(h,fid\);
        FwpmSubLayerDeleteByKey0\(h,ref subkey\);
        FwpmEngineClose0\(h\);
        return sb.ToString\(\);
    }
}
