    static IntPtr BF\(Guid fk,IntPtr nm,Guid lk,Guid sk,uint nc,IntPtr cp,uint at\){
        IntPtr p=Marshal.AllocHGlobal\(200\);for\(int i=0;i<200;i++\)Marshal.WriteByte\(p,i,0\);
        WG\(p,0,fk\);WP\(p,16,nm\);WG\(p,64,lk\);WG\(p,80,sk\);
        Marshal.WriteInt32\(p,112,\(int\)nc\);WP\(p,120,cp\);Marshal.WriteInt32\(p,128,\(int\)at\);return p;}

    // Build condition with uint32Value at a specific byte offset within the condition buffer
    static IntPtr BCV\(Guid field, uint ip, int valOffset\) {
        IntPtr p=Marshal.AllocHGlobal\(48\);for\(int i=0;i<48;i++\)Marshal.WriteByte\(p,i,0\);
        WG\(p,0,field\);
        Marshal.WriteInt32\(p,16,0\); // matchType=FWP_MATCH_EQUAL
        Marshal.WriteInt32\(p,24,3\); // conditionValue.type=FWP_UINT32
        Marshal.WriteInt32\(p,valOffset,\(int\)ip\);
        return p;
    }

    public static string Run\(\) {
        IntPtr h;
        FwpmEngineOpen0\(IntPtr.Zero,0xFFFFFFFF,IntPtr.Zero,IntPtr.Zero,out h\);
        Guid layer=new Guid\(\\"c38d57d1-05a7-4c33-904f-7fbceee60e82\\"\);
        Guid subkey=new Guid\(\\"dbd00003-0000-0000-0000-000000000001\\"\);
        Guid ipF=new Guid\(\\"4cd62a49-59c3-4969-b7f3-bda5d32890a4\\"\);
        uint ip=0x01010101;
        FWPM_SUBLAYER0 sl=new FWPM_SUBLAYER0\(\);sl.subLayerKey=subkey;
