        FwpmSubLayerAdd0\(h,ref sl,IntPtr.Zero\);Marshal.FreeHGlobal\(snm\);

        var sb=new StringBuilder\(\);
        // Try uint32 at offsets 24+4=28, 24+8=32 \(current\), 24+12=36
        foreach\(int off in new[]{28,32,36}\) {
            IntPtr cp=BCV\(ipF,ip,off\);
            IntPtr nm=Marshal.StringToHGlobalUni\(\\"DBD-T\\"\);
            IntPtr fp=BF\(new Guid\(\\"dbd00003-0000-0000-\\"+off.ToString\(\\"0000\\"\)+\\"-000000000001\\"\),nm,layer,subkey,1,cp,0x1001\);
            ulong fid;uint r=FwpmFilterAdd0\(h,fp,IntPtr.Zero,out fid\);
            Marshal.FreeHGlobal\(fp\);Marshal.FreeHGlobal\(nm\);Marshal.FreeHGlobal\(cp\);
            sb.Append\(\\"valOffset=\\"+off+\\" -> 0x\\"+r.ToString\(\\"X8\\"\)\);
            if\(r==0\){sb.Append\(\\" OK fid=\\"+fid\);FwpmFilterDeleteById0\(h,fid\);}
            sb.Append\(\\"\\\\n\\"\);
        }
        FwpmSubLayerDeleteByKey0\(h,ref subkey\);
        FwpmEngineClose0\(h\);
        return sb.ToString\(\);
    }
}
