using System; using System.Runtime.InteropServices; using System.Text;
public static class WC {
    [DllImport\(\\"fwpuclnt.dll\\"\)] static extern uint FwpmEngineOpen0\(IntPtr s,uint a,IntPtr i,IntPtr se,out IntPtr h\);
    [DllImport\(\\"fwpuclnt.dll\\"\)] static extern uint FwpmEngineClose0\(IntPtr h\);
    [DllImport\(\\"fwpuclnt.dll\\"\)] static extern uint FwpmFilterGetById0\(IntPtr h,ulong id,out IntPtr filter\);
    [DllImport\(\\"fwpuclnt.dll\\"\)] static extern void FwpmFreeMemory0\(ref IntPtr p\);
    public static string DumpCond\(ulong fid\) {
        IntPtr h; FwpmEngineOpen0\(IntPtr.Zero,0xFFFFFFFF,IntPtr.Zero,IntPtr.Zero,out h\);
        IntPtr fp=IntPtr.Zero;
        uint r=FwpmFilterGetById0\(h,fid,out fp\);
        if\(r!=0\){FwpmEngineClose0\(h\);return \\"GetById fail 0x\\"+r.ToString\(\\"X8\\"\);}
        // filterCondition ptr is at offset 120 in FWPM_FILTER0
        IntPtr condPtr = new IntPtr\(Marshal.ReadInt64\(fp, 120\)\);
        // numFilterConditions at offset 112
        int numCond = Marshal.ReadInt32\(fp, 112\);
        var sb = new StringBuilder\(\);
        sb.AppendFormat\(\\"numCond={0}, condPtr=0x{1:X}\\\\n\\", numCond, condPtr.ToInt64\(\)\);
        if \(condPtr != IntPtr.Zero && numCond > 0\) {
            sb.Append\(\\"Condition bytes \(48\):\\\\n\\"\);
            for\(int i=0;i<48;i++\){
                sb.AppendFormat\(\\"{0:x2}\\",Marshal.ReadByte\(condPtr,i\)\);
                if\(\(i+1\)%4==0\) sb.Append\(\\" \\"\);
                if\(\(i+1\)%16==0\) sb.Append\(\\" off=\\"+\(i-14\)+\\"\\\\n\\"\);
            }
        }
        FwpmFreeMemory0\(ref fp\);
        FwpmEngineClose0\(h\);
        return sb.ToString\(\);
    }
}
'@
[WC]::DumpCond\(\\$fid\)
Remove-NetFirewallRule -DisplayName 'DBD_COND_DUMP' -ErrorAction SilentlyContinue
" 2>&1)
